export type CSVValue = string | number | boolean | null;
export type CSVRow = Record<string, CSVValue>;

export interface CSVOptions {
  delimiter?: string;
  quote?: string;
  lineSeparator?: string;
}

export interface CSVError {
  row: number;
  message: string;
}

export interface CSVResult {
  rows: CSVRow[];
  headers: string[];
  errors: CSVError[];
  filter(predicate: (row: CSVRow, index: number) => boolean): CSVRow[];
  sum(column: string): number;
  average(column: string): number;
  count(): number;
  groupBy(column: string): Map<CSVValue, CSVRow[]>;
}

const DEFAULT_OPTIONS: Required<CSVOptions> = {
  delimiter: ',',
  quote: '"',
  lineSeparator: '\n',
};

function isNumericString(value: string): boolean {
  return /^-?\d+(\.\d+)?$/.test(value); // integers and floats
}

function coerceValue(field: string): CSVValue {
  const normalized = field.trim();
  if (normalized === '') {
    return null;
  }

  const lower = normalized.toLowerCase();
  if (lower === 'null') {
    return null;
  }

  if (lower === 'true') {
    return true;
  }

  if (lower === 'false') {
    return false;
  }

  if (isNumericString(normalized)) {
    const num = Number(normalized);
    return Number.isNaN(num) ? normalized : num;
  }

  return normalized;
}

export function parseCSV(input: string, options?: CSVOptions): CSVResult {
  if (input == null || input === '') {
    const emptyResult = buildResult([], [], []);
    return emptyResult;
  }

  let buffer = input;
  if (buffer.charCodeAt(0) === 0xfeff) {
    buffer = buffer.slice(1);
  }

  const config = { ...DEFAULT_OPTIONS, ...options };
  const { delimiter, quote, lineSeparator } = config;

  const rows: CSVRow[] = [];
  const errors: CSVError[] = [];
  const headers: string[] = [];

  let currentField = '';
  let currentFields: string[] = [];
  let inQuotes = false;
  let headerProcessed = false;
  let rowNumber = 1;

  const finalizeRow = () => {
    currentFields.push(currentField);
    currentField = '';

    const thisRowFields = currentFields;
    currentFields = [];

    const thisRowNumber = rowNumber;
    rowNumber += 1;

    if (!headerProcessed) {
      headers.push(...thisRowFields);
      headerProcessed = true;
      return;
    }

    if (thisRowFields.length !== headers.length) {
      errors.push({
        row: thisRowNumber,
        message: `Expected ${headers.length} fields but got ${thisRowFields.length}`,
      });
      return;
    }

    const record: CSVRow = {};
    for (let i = 0; i < headers.length; i++) {
      record[headers[i]] = coerceValue(thisRowFields[i] ?? '');
    }

    rows.push(record);
  };

  const hasLineSeparator = lineSeparator && lineSeparator.length > 0;

  let i = 0;
  const length = buffer.length;

  while (i < length) {
    const char = buffer[i];

    if (!inQuotes) {
      if (hasLineSeparator && buffer.startsWith(lineSeparator, i)) {
        finalizeRow();
        i += lineSeparator.length;
        continue;
      }

      if (lineSeparator === '\n' && char === '\r') {
        finalizeRow();
        if (i + 1 < length && buffer[i + 1] === '\n') {
          i += 2;
        } else {
          i += 1;
        }
        continue;
      }

      if (delimiter && delimiter.length > 0 && buffer.startsWith(delimiter, i)) {
        currentFields.push(currentField);
        currentField = '';
        i += delimiter.length;
        continue;
      }
    }

    if (char === quote) {
      const nextChar = buffer[i + 1];
      if (inQuotes && nextChar === quote) {
        currentField += quote;
        i += 2;
        continue;
      }

      inQuotes = !inQuotes;
      i += 1;
      continue;
    }

    currentField += char;
    i += 1;
  }

  if (inQuotes) {
    errors.push({
      row: rowNumber,
      message: 'Unterminated quoted field',
    });
    inQuotes = false;
  }

  const pendingFields = currentFields.length > 0 || currentField !== '';
  if (pendingFields) {
    finalizeRow();
  }

  return buildResult(rows, headers, errors);
}

function buildResult(rows: CSVRow[], headers: string[], errors: CSVError[]): CSVResult {
  const result: CSVResult = {
    rows,
    headers,
    errors,
    filter(predicate) {
      return result.rows.filter(predicate);
    },
    sum(column) {
      return result.rows.reduce((total, row) => {
        const value = row[column];
        if (typeof value === 'number' && !Number.isNaN(value)) {
          return total + value;
        }
        return total;
      }, 0);
    },
    average(column) {
      let total = 0;
      let count = 0;
      for (const row of result.rows) {
        const value = row[column];
        if (typeof value === 'number' && !Number.isNaN(value)) {
          total += value;
          count += 1;
        }
      }
      return count === 0 ? 0 : total / count;
    },
    count() {
      return result.rows.length;
    },
    groupBy(column) {
      const groups = new Map<CSVValue, CSVRow[]>();
      for (const row of result.rows) {
        const key = row[column];
        if (!groups.has(key)) {
          groups.set(key, []);
        }
        groups.get(key)!.push(row);
      }
      return groups;
    },
  };

  return result;
}
