import { parseCSV } from './csv-parser';

function assert(condition: boolean, message?: string): void {
  if (!condition) {
    throw new Error(message ?? 'Assertion failed');
  }
}

function runTest(testName: string, fn: () => void): void {
  try {
    fn();
    console.log(`✔️  ${testName}`);
  } catch (error) {
    console.error(`❌  ${testName}`);
    throw error;
  }
}

function testBasicParsing(): void {
  const csv = 'name,age\nAlice,30\nBob,25';
  const result = parseCSV(csv);

  assert(result.headers.length === 2, 'Headers should include two values');
  assert(result.headers[0] === 'name');
  assert(result.headers[1] === 'age');

  assert(result.rows.length === 2, 'Should parse two data rows');
  assert(result.rows[0].name === 'Alice');
  assert(result.rows[0].age === 30);
  assert(result.rows[1].name === 'Bob');
  assert(result.rows[1].age === 25);

  assert(result.sum('age') === 55, 'Sum of ages should be 55');
  assert(result.average('age') === 27.5, 'Average age should be 27.5');
  assert(result.count() === 2, 'Count should be 2');
}

function testQuotedFields(): void {
  const csv = 'name,quote\n"Smith, John","Hello, world!"';
  const result = parseCSV(csv);

  assert(result.rows.length === 1);
  assert(result.rows[0].name === 'Smith, John');
  assert(result.rows[0].quote === 'Hello, world!');
}

function testEscapedQuotes(): void {
  const csv = 'speaker,message\n"Jane","She said ""Hi"" to everyone"';
  const result = parseCSV(csv);

  assert(result.rows.length === 1);
  assert(result.rows[0].message === 'She said "Hi" to everyone');
}

function testCustomDelimiters(): void {
  const csv = "id|note||1|'Hello|World'||2|'It''s me'";
  const result = parseCSV(csv, { delimiter: '|', quote: "'", lineSeparator: '||' });

  assert(result.headers[0] === 'id');
  assert(result.headers[1] === 'note');
  assert(result.rows.length === 2);
  assert(result.rows[0].note === 'Hello|World');
  assert(result.rows[1].note === "It's me");
}

function testTypeCoercion(): void {
  const csv = 'value,bool,nullval,text\n42,TRUE,null,hello\n-5.25,false,NULL,"  important  "\n,TRUE,,\n';
  const result = parseCSV(csv);

  const [first, second, third] = result.rows;
  assert(first.value === 42);
  assert(first.bool === true);
  assert(first.nullval === null);
  assert(first.text === 'hello');

  assert(second.value === -5.25);
  assert(second.bool === false);
  assert(second.nullval === null);
  assert(second.text === 'important');

  assert(third.value === null);
  assert(third.bool === true);
  assert(third.nullval === null);
  assert(third.text === null);
}

function testMalformedRowErrors(): void {
  const csv = 'a,b\n1\n2,3';
  const result = parseCSV(csv);

  assert(result.rows.length === 1, 'Only rows with correct column counts should be returned');
  assert(result.rows[0].a === 2);
  assert(result.rows[0].b === 3);

  assert(result.errors.length === 1);
  assert(result.errors[0].row === 2);
  assert(result.errors[0].message.includes('Expected 2 fields but got 1'));
}

function testFilterFunctionality(): void {
  const csv = 'name,active\nAlice,true\nBob,false\nCarol,true';
  const result = parseCSV(csv);

  const filtered = result.filter((row) => row.active === true);
  assert(filtered.length === 2);
  assert(filtered.some((row) => row.name === 'Alice'));
  assert(filtered.some((row) => row.name === 'Carol'));
  assert(result.count() === 3);
}

function testAggregationMethods(): void {
  const csv = 'group,value\nA,10\nA,5\nB,3\nB,7\nC,8';
  const result = parseCSV(csv);

  assert(result.sum('value') === 33);
  assert(Math.abs(result.average('value') - 6.6) < 1e-9);
  assert(result.count() === 5);

  const grouped = result.groupBy('group');
  assert(grouped.size === 3);
  assert(grouped.get('A')!.length === 2);
  assert(grouped.get('B')!.length === 2);
  assert(grouped.get('C')!.length === 1);
}

function testEdgeCases(): void {
  const empty = parseCSV('');
  assert(empty.count() === 0);
  assert(empty.headers.length === 0);
  assert(empty.errors.length === 0);

  const single = parseCSV('only\nvalue');
  assert(single.headers[0] === 'only');
  assert(single.rows.length === 1);
  assert(single.rows[0].only === 'value');

  const large = 'x'.repeat(15000);
  const huge = parseCSV(`id,text\n1,${large}`);
  assert(huge.rows[0].text === large);
}

const tests: Array<[string, () => void]> = [
  ['basic parsing', testBasicParsing],
  ['quoted fields', testQuotedFields],
  ['escaped quotes', testEscapedQuotes],
  ['custom delimiters', testCustomDelimiters],
  ['type coercion', testTypeCoercion],
  ['malformed row errors', testMalformedRowErrors],
  ['filter functionality', testFilterFunctionality],
  ['aggregation methods', testAggregationMethods],
  ['edge cases', testEdgeCases],
];

function runAllTests(): void {
  for (const [name, fn] of tests) {
    runTest(name, fn);
  }
  console.log('All csv-parser tests passed');
}

runAllTests();

